import React, { useState } from "react";
import { Container, Paper, Typography, TextField, Button, Alert, Box, CircularProgress } from "@mui/material";
import { useNavigate } from "react-router-dom";
import api from "../services/api";

export default function Login() {
  const navigate = useNavigate();
  const [mobile, setMobile] = useState("");
  const [error, setError] = useState("");
  const [loading, setLoading] = useState(false);

  const validateMobile = () => {
    const mobileRegex = /^[6-9]\d{9}$/;
    if (!mobileRegex.test(mobile)) {
      setError("Mobile number must start with 6-9 and be 10 digits long.");
      return false;
    }
    setError("");
    return true;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validateMobile()) return;

    try {
      setLoading(true);
      const res = await api.login(mobile);

      if (res.success) {
        setError("");
        navigate("/dashboard"); // redirect to dashboard
      } else {
        setError(res.message || "Login failed");
      }
    } catch (err) {
      setError("Server error. Please try again later.");
    } finally {
      setLoading(false);
    }
  };

  return (
    <Container maxWidth="sm">
      <Paper elevation={3} sx={{ p: 4, mt: 5, borderRadius: 3 }}>
        <Typography variant="h4" align="center" sx={{ color: "orangered", fontWeight: "bold" }}>Rider App</Typography>
        <Typography align="center" sx={{ mb: 3 }}>Welcome back! Please login</Typography>

        {error && <Alert severity="error" sx={{ mb: 2 }}>{error}</Alert>}

        <Box component="form" onSubmit={handleSubmit}>
          <TextField
            fullWidth
            label="Mobile Number"
            type="tel"
            value={mobile}
            onChange={(e) => setMobile(e.target.value)}
            margin="normal"
            inputProps={{ maxLength: 10 }}
            required
          />

          <Button
            type="submit"
            fullWidth
            variant="contained"
            sx={{ mt: 2, bgcolor: "orangered", "&:hover": { bgcolor: "darkred" } }}
            disabled={loading}
          >
            {loading ? <CircularProgress size={24} sx={{ color: "white" }} /> : "Login"}
          </Button>
        </Box>

        <Typography align="center" sx={{ mt: 2 }}>
          Don’t have an account?{" "}
          <Button variant="text" onClick={() => navigate("/signup")} sx={{ color: "orangered" }}>Sign Up</Button>
        </Typography>
      </Paper>
    </Container>
  );
}
